// Rotate through product categories to ensure variety
const categories = [
  "kitchen gadgets",
  "home organization",
  "travel accessories",
  "student essentials"
];

// Use execution ID and timestamp to create pseudo-random but deterministic rotation
const executionId = $execution.id || "";
const timestamp = Date.now();
const seed = executionId.split("").reduce((acc, char) => acc + char.charCodeAt(0), 0) + timestamp;
const categoryIndex = seed % categories.length;

const selectedCategory = categories[categoryIndex];

return [{ json: { category: selectedCategory, executionId: $execution.id, timestamp: timestamp } }];

const products = $json.search_results || [];

return [{
json: {
products: products.map(p => ({
title: p.title,
link: p.link,
rating: p.rating,
reviews: p.ratings_total,
price: p.price?.value,
image: p.image
}))
}
}];

const products = JSON.parse($json.output);

return products.map(product => ({
json: product
}));
